app.get('/introspect', async (req, res) => {
  const token = req.query.token;
  if (!token) return res.status(400).json({ active: false });

  try {
    const payload = jwt.verify(token, JWT_SECRET, { issuer: ISSUER });
    return res.json({
      active: true,
      sub: payload.sub,
      aud: payload.aud,
      scope: payload.scope,
      exp: payload.exp,
      iat: payload.iat,
      iss: payload.iss,
      token_type: 'access_token',
    });
  } catch {
    return res.json({ active: false });
  }
});

app.post('/revoke', async (req, res) => {
  const clientAuth = validateClient(req);
  if (!clientAuth) return res.status(401).json({ error: 'invalid_client' });

  const token = req.body.token;
  if (!token) return res.status(400).json({ error: 'invalid_request' });

  const refreshKey = `refresh:${token}`;
  const stored = await redis.get(refreshKey);
  if (stored) {
    const data = JSON.parse(stored);
    if (data.client_id === clientAuth.clientId) {
      await redis.del(refreshKey);
    }
  }

  return res.status(200).end();
});

